sourceQuery.rawQuery:
SELECT COUNT(*) AS EosAssetCount
FROM `AST:ComputerSystem`
WHERE `Supported` = 'No';

SELECT COUNT(*) AS EolAssetCount
FROM `AST:ComputerSystem`
WHERE `AssetLifecycleStatus` = 'Disposed';

SELECT (COUNT(*)*1.00 / (SELECT COUNT(*) FROM `AST:ComputerSystem` WHERE `AssetLifecycleStatus` = 'Deployed')) * 100 AS AssetComplianceScore
FROM `AST:ComputerSystem`
WHERE `AssetLifecycleStatus` = 'Deployed' AND `Supported` = 'Yes';

SELECT (COUNT(*)*1.00 / (SELECT COUNT(*) FROM `AST:ComputerSystem`)) * 100 AS AssetUtilizationPercentage
FROM `AST:ComputerSystem`
WHERE `AssetLifecycleStatus` IN('Deployed');

SELECT AVG(DATEDIFF('dd',`Start Date`,`Expiration Date`)) AS AvgContractDuration
FROM `AR System Schema`.`CTR:Contract_Base_locale_MenuItems`
WHERE `Status` = 'Executed';

SELECT (COUNT(*)*1.00 / (SELECT COUNT(*) FROM `AST:ComputerSystem`)) * 100 AS AssetRetirementRate
FROM `AST:ComputerSystem`
WHERE `AssetLifecycleStatus` = 'Disposed';

SELECT DISTINCT
  COUNT(`CTR:Contract_Base_locale_MenuItems`.`Contract ID+`)
FROM `AR System Schema`.`CTR:Contract_Base_locale_MenuItems` 
WHERE (
   `CTR:Contract_Base_locale_MenuItems`.`Locale` IS NULL
)
AND (
`CTR:Contract_Base_locale_MenuItems`.`Status`= 'Executed'
)

)
